func TestBQ_EnqueueDequeue(t *testing.T) {
	q := NewBoundedQueue(10)
	q.Enqueue("hello")
	item, ok := q.Dequeue()
	if !ok || item != "hello" {
		t.Fatal("expected hello")
	}
