func TestBQ_FIFO(t *testing.T) {
	q := NewBoundedQueue(10)
	q.Enqueue("a")
	q.Enqueue("b")
	q.Enqueue("c")
	v1, _ := q.Dequeue()
	v2, _ := q.Dequeue()
