	SuspicionTimeout time.Duration
}

// DefaultSWIMConfig returns reasonable defaults.
func DefaultSWIMConfig() SWIMConfig {
	return SWIMConfig{
		ProbeInterval:    time.Second,
		ProbeTimeout:     500 * time.Millisecond,
		IndirectChecks:   3,
		SuspicionTimeout: 5 * time.Second,
	}
