func TestWSP_ConcurrentSteals_UpdateStolenCount(t *testing.T) {
	p := NewWorkStealingPool()
	p.Register("owner")
	thiefIDs := []string{"t0", "t1", "t2", "t3", "t4", "t5", "t6", "t7"}
	for _, thiefID := range thiefIDs {
		p.Register(thiefID)
	}

	const total = 1000
	for i := 0; i < total; i++ {
		if !p.Submit("owner", i) {
			t.Fatal("submit failed")
		}
	}

	results := make(chan int, total)
	var wg sync.WaitGroup
	for _, thiefID := range thiefIDs {
		thiefID := thiefID
		wg.Add(1)
		go func() {
			defer wg.Done()
			for {
				item, _, ok := p.Steal(thiefID)
				if !ok {
					return
				}
				results <- item.(int)
			}
		}()
	}
	wg.Wait()
	close(results)

	seen := make([]bool, total)
	count := 0
	for item := range results {
		if item < 0 || item >= total {
			t.Fatalf("item out of range: %d", item)
		}
		if seen[item] {
			t.Fatalf("duplicate item: %d", item)
		}
		seen[item] = true
		count++
	}
	if count != total {
		t.Fatalf("expected %d stolen items, got %d", total, count)
	}
	if p.StolenCount() != total {
		t.Fatalf("expected stolen count %d, got %d", total, p.StolenCount())
	}
}
